- Per-page state machines and atomic publish
- I-cache/TLB synchronization and rollback safety

## Code Example

```javascript
// Minimal C-like sketch (pseudo-code)
enum { STABLE, STAGED, ACTIVE } state_t;
typedef struct { void *addr; void *code; state_t s; volatile int refcnt; uint64_t ver; } page_t;

int publish_patch(page_t *p, void *new_code) {
  p->s = STAGED;
  p->code = new_code;
  __sync_synchronize();
  if (atomic_compare_exchange(&p->s, STAGED, ACTIVE)) {
    atomic_fetch_add(&p->ver, 1);
    icache_invalidate(p->addr, PAGE_SIZE);
    tlb_invalidate(p->addr, PAGE_SIZE);
    return 0;
  }
  return -1;
}
```

