## Code Example

```javascript
// Pseudo-C code: per-block cache entry
const BLOCK_SIZE = 4096;
const NUM_BLOCKS = 1024;
const STATE_EMPTY = 0, STATE_LOADING = 1, STATE_LOADED = 2;

struct Block {
  atomicInt state;
  char data[BLOCK_SIZE];
  bool dirty;
  Mutex m;        // for waiters
  CondVar cv;
};

Block cache[NUM_BLOCKS];

// fetchBlock(bid) pseudo
Block* fetchBlock(int bid) {
  Block* b = &cache[bid];
  if (atomicLoad(&b->state) == STATE_LOADED) return b;
  int expected = STATE_EMPTY;
  if (atomicCompareExchange(&b->state, &expected, STATE_LOADING)) {
    // load from disk
    readFromDisk(bid, b->data);
    atomicStore(&b->state, STATE_LOADED);
    signalAll(&b->cv);
  } else {
    // wait until loaded
    lock(&b->m);
    while (atomicLoad(&b->state) != STATE_LOADED) wait(&b->cv, &b->m);
    unlock(&b->m);
  }
  return b;
}
```

